/**
 * Audit Trail Generation Stage
 *
 * Stage 9+ (post-processing) of the EmailCategorizer pipeline. Generates complete
 * explainability traces consolidating results from all 9 classification pipeline stages.
 *
 * This stage is responsible for:
 * - Aggregating results from all pipeline stages into a unified explainability trace
 * - Tracking performance metadata (stage timings, parallel execution maps)
 * - Collecting configuration references used throughout the pipeline
 * - Generating final decision rationale summarizing the complete classification process
 * - Producing database-compatible JSON format for persistence
 *
 * Reference: PrepareRuleScoringPersistenceNode.js and other Prepare*PersistenceNode.js files
 * Document: SCORING_LOGIC.md "Explainability Trace Structure" section
 */

import { z } from 'zod';
import { EmailMessage, ClassificationSession } from '../types';
import {
  ExplainabilityTrace,
  HardAssertionResult,
  StrongIndicatorResult,
  RuleEvaluationResult,
  AttributeDetectionResult,
  AttributeInfluenceResult,
  DisambiguationResult,
  MultiLabelResult as ExplainMultiLabelResult,
  AIRoutingResult,
} from '../types/explainability-trace';
import { MultiLabelSelectionResult } from './types';
import { FinalDecisionResult } from './final-decision';

// Zod schema for audit trail configuration
export const AuditTrailConfigSchema = z.object({
  includePerformanceMetrics: z.boolean().default(true),
  includeConfigurationRefs: z.boolean().default(true),
  serializationFormat: z.enum(['json', 'jsonb']).default('json'),
});

// Configuration interface for audit trail generation
export interface AuditTrailConfig {
  includePerformanceMetrics: boolean;
  includeConfigurationRefs: boolean;
  serializationFormat: 'json' | 'jsonb';
}

// Pipeline results interface aggregating all stage outputs
export interface PipelineResults {
  hardAssertions: HardAssertionsStageResult;
  strongIndicators: StrongIndicatorsStageResult;
  ruleScoring: RuleScoringStageResult;
  attributeDetection: AttributeDetectionStageResult;
  attributeInfluence: AttributeInfluenceStageResult;
  disambiguation: DisambiguationStageResult;
  multiLabelSelection: MultiLabelSelectionResult;
  aiRouting: AIRoutingStageResult;
  finalDecision: FinalDecisionResult;
}

// Individual stage result interfaces
export interface HardAssertionsStageResult {
  appliedAssertions: HardAssertionResult[];
  processingDurationMs: number;
}

export interface StrongIndicatorsStageResult {
  appliedIndicators: StrongIndicatorResult[];
  processingDurationMs: number;
}

export interface RuleScoringStageResult {
  categoryScores: Record<string, number>;
  subtypeScores: Record<string, Record<string, number>>;
  ruleMatches?: RuleEvaluationResult[];
  processingDurationMs: number;
}

export interface AttributeDetectionStageResult {
  detectedAttributes: AttributeDetectionResult[];
  processingDurationMs: number;
}

export interface AttributeInfluenceStageResult {
  appliedInfluences: AttributeInfluenceResult[];
  processingDurationMs: number;
}

export interface DisambiguationStageResult {
  adjustments: DisambiguationResult[];
  processingDurationMs: number;
}

export interface AIRoutingStageResult {
  routingDecision: 'skip_ai' | 'feature_extraction' | 'full_classification';
  highConfidenceThreshold: number;
  aiRequiredThreshold: number;
  skipConditions: string[];
  aiResponse?: {
    extractedFeatures?: object;
    suggestedCategories?: string[];
    confidence: number;
    reasoning: string;
  };
  reason: string;
  processingDurationMs: number;
}

// Complete audit trail result
export interface AuditTrailResult {
  sessionId: string;
  emailId: string;
  explainabilityTrace: ExplainabilityTrace;
  processingDurationMs: number;
}

/**
 * Generate Audit Trail
 *
 * Consolidates results from all 9 pipeline stages into a complete explainability trace
 * for database persistence and debugging purposes.
 *
 * @param email - Email message being classified
 * @param session - Classification session metadata
 * @param pipelineResults - Results from all 9 pipeline stages
 * @param config - Audit trail configuration
 * @returns Complete audit trail with explainability trace
 */
export function generateAuditTrail(
  email: EmailMessage,
  session: ClassificationSession,
  pipelineResults: PipelineResults,
  config: AuditTrailConfig
): AuditTrailResult {
  const startTime = Date.now();

  // Validate inputs
  validateInputs(email, session, pipelineResults);

  // Extract session and email IDs (support both id and legacy _id formats)
  const sessionId = session.id || ((session as unknown as Record<string, unknown>).session_id as string);
  const emailId = email.id || ((email as unknown as Record<string, unknown>).gmail_id as string);

  // Aggregate stage timings
  const stageTimings = aggregateStageTimings(pipelineResults);

  // Build parallel execution map
  const parallelExecutionMap = buildParallelExecutionMap(pipelineResults);

  // Collect configuration references
  const configurationRefs = config.includeConfigurationRefs ? collectConfigurationReferences(pipelineResults) : {};

  // Generate final decision reason
  const finalDecisionReason = generateFinalDecisionReason(pipelineResults);

  // Extract alternative categories
  const alternativeCategories = extractAlternativeCategories(pipelineResults);

  // Convert multi-label selection results to explainability format
  const multiLabelResults = convertMultiLabelResults(pipelineResults.multiLabelSelection);

  // Build AI routing result
  const aiRoutingResult = buildAIRoutingResult(pipelineResults.aiRouting);

  // Construct complete explainability trace
  const explainabilityTrace: ExplainabilityTrace = {
    sessionId,
    emailId,
    hardAssertions: pipelineResults.hardAssertions.appliedAssertions,
    strongIndicators: pipelineResults.strongIndicators.appliedIndicators,
    ruleScoring: pipelineResults.ruleScoring.ruleMatches || [],
    attributeDetection: pipelineResults.attributeDetection.detectedAttributes,
    attributeInfluence: pipelineResults.attributeInfluence.appliedInfluences,
    disambiguation: pipelineResults.disambiguation.adjustments,
    multiLabelSelection: multiLabelResults,
    aiRouting: aiRoutingResult,
    stageTimings,
    parallelExecutionMap,
    configurationRefs,
    finalDecisionReason,
    alternativeCategories,
  };

  return {
    sessionId,
    emailId,
    explainabilityTrace,
    processingDurationMs: Date.now() - startTime,
  };
}

/**
 * Validate input parameters
 */
function validateInputs(email: EmailMessage, session: ClassificationSession, pipelineResults: PipelineResults): void {
  if (!email || (!email.id && !(email as unknown as Record<string, unknown>).gmail_id)) {
    throw new Error('Invalid email input: id or gmail_id is required');
  }

  if (!session || (!session.id && !(session as unknown as Record<string, unknown>).session_id)) {
    throw new Error('Invalid session input: id or session_id is required');
  }

  if (!pipelineResults || typeof pipelineResults !== 'object') {
    throw new Error('Invalid pipeline results: object required');
  }

  // Validate required stages
  const requiredStages = [
    'hardAssertions',
    'strongIndicators',
    'ruleScoring',
    'attributeDetection',
    'attributeInfluence',
    'disambiguation',
    'multiLabelSelection',
    'aiRouting',
    'finalDecision',
  ];

  for (const stage of requiredStages) {
    if (!pipelineResults[stage as keyof PipelineResults]) {
      throw new Error(`Missing required pipeline stage: ${stage}`);
    }
  }
}

/**
 * Aggregate stage timings from all pipeline stages
 */
function aggregateStageTimings(pipelineResults: PipelineResults): Record<string, number> {
  return {
    hardAssertions: pipelineResults.hardAssertions.processingDurationMs,
    strongIndicators: pipelineResults.strongIndicators.processingDurationMs,
    ruleScoring: pipelineResults.ruleScoring.processingDurationMs,
    attributeDetection: pipelineResults.attributeDetection.processingDurationMs,
    attributeInfluence: pipelineResults.attributeInfluence.processingDurationMs,
    disambiguation: pipelineResults.disambiguation.processingDurationMs,
    multiLabelSelection: pipelineResults.multiLabelSelection.processingDurationMs,
    aiRouting: pipelineResults.aiRouting.processingDurationMs,
    finalDecision: pipelineResults.finalDecision.processingDurationMs,
  };
}

/**
 * Build parallel execution map tracking which stages/attributes ran concurrently
 */
function buildParallelExecutionMap(pipelineResults: PipelineResults): Record<string, string[]> {
  const parallelMap: Record<string, string[]> = {};

  // Track parallel-processed attributes from attribute detection stage
  const parallelAttributes = pipelineResults.attributeDetection.detectedAttributes
    .filter((attr) => attr.parallelProcessed)
    .map((attr) => attr.attribute);

  if (parallelAttributes.length > 0) {
    parallelMap.attributeDetection = parallelAttributes;
  }

  return parallelMap;
}

/**
 * Collect configuration references used throughout the pipeline
 */
function collectConfigurationReferences(pipelineResults: PipelineResults): Record<string, string> {
  const refs: Record<string, string> = {};

  // Hard assertions config
  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
    refs.hardAssertions = 'config.processing_config.category_signals.*.hard_assertions';
  }

  // Strong indicators config
  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
    refs.strongIndicators = 'config.processing_config.category_signals.*.strong_indicators';
  }

  // Rule scoring config
  if (Object.keys(pipelineResults.ruleScoring.categoryScores).length > 0) {
    refs.ruleScoring = 'config.processing_config.top_level_categories.*.subtypes.*.rule_based_classification';
  }

  // Attribute detection config
  if (pipelineResults.attributeDetection.detectedAttributes.length > 0) {
    refs.attributeDetection = 'config.processing_config.attributes.detectors';
  }

  // Attribute influence config
  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
    refs.attributeInfluence = 'config.processing_config.attribute_relevance';
  }

  // Disambiguation config
  if (pipelineResults.disambiguation.adjustments.length > 0) {
    refs.disambiguation = 'config.processing_config.settings.disambiguation.confidence_gap_threshold';
  }

  // Multi-label selection config
  refs.multiLabelSelection = 'config.processing_config.multi_label_policy';

  // AI routing config
  refs.aiRouting = 'config.processing_config.confidence_thresholds';

  // Final decision config
  refs.finalDecision = 'config.processing_config.settings.archive_threshold';

  return refs;
}

/**
 * Generate final decision reason summarizing the complete classification pipeline
 */
function generateFinalDecisionReason(pipelineResults: PipelineResults): string {
  const reasons: string[] = [];

  // Check for hard assertions (highest priority)
  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
    const categories = pipelineResults.hardAssertions.appliedAssertions.map((a) => a.category);
    reasons.push(`Hard assertion matched for categories: ${[...new Set(categories)].join(', ')}`);
  }

  // Check for strong indicators
  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
    const categories = pipelineResults.strongIndicators.appliedIndicators.map((i) => i.category);
    reasons.push(`Strong indicators detected for: ${[...new Set(categories)].join(', ')}`);
  }

  // Include rule scoring results
  const topCategories = Object.entries(pipelineResults.ruleScoring.categoryScores)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3);

  if (topCategories.length > 0) {
    const categoryScores = topCategories.map(([cat, score]) => `${cat}:${score.toFixed(1)}`).join(', ');
    reasons.push(`Top rule-based scores: ${categoryScores}`);
  }

  // Include attribute influences
  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
    const attributeCount = pipelineResults.attributeInfluence.appliedInfluences.length;
    reasons.push(`${attributeCount} attribute bonuses applied`);
  }

  // Include AI routing decision
  if (pipelineResults.aiRouting.routingDecision !== 'skip_ai') {
    reasons.push(`AI classification used: ${pipelineResults.aiRouting.reason}`);
  }

  // Include final decision
  const finalLabels = pipelineResults.finalDecision.assignedLabels;
  reasons.push(`Final assignment: primary=${finalLabels.primary}, secondary=[${finalLabels.secondary.join(', ')}]`);

  if (pipelineResults.finalDecision.determinedActions.length > 0) {
    reasons.push(`Actions: ${pipelineResults.finalDecision.determinedActions.join(', ')}`);
  }

  return reasons.join('; ');
}

/**
 * Extract alternative categories that were not selected
 */
function extractAlternativeCategories(pipelineResults: PipelineResults): Array<{
  category: string;
  score: number;
  eliminationReason: string;
}> {
  const alternatives: Array<{
    category: string;
    score: number;
    eliminationReason: string;
  }> = [];

  const finalPrimary = pipelineResults.finalDecision.assignedLabels.primary;
  const finalSecondary = pipelineResults.finalDecision.assignedLabels.secondary;
  const selectedCategories = [finalPrimary, ...finalSecondary];

  // Get all categories from rule scoring
  const allCategories = Object.entries(pipelineResults.ruleScoring.categoryScores);

  for (const [category, score] of allCategories) {
    if (!selectedCategories.includes(category)) {
      let eliminationReason = 'Score below selection threshold';

      // Check if filtered by multi-label selection
      const filteredLabels = pipelineResults.finalDecision.explainabilityTrace.filteredLabels || [];
      const wasFiltered = filteredLabels.find((f) => f.category === category);
      if (wasFiltered) {
        eliminationReason = wasFiltered.filterReason;
      }

      alternatives.push({
        category,
        score,
        eliminationReason,
      });
    }
  }

  // Sort by score descending
  alternatives.sort((a, b) => b.score - a.score);

  return alternatives;
}

/**
 * Convert multi-label selection results to explainability format
 */
function convertMultiLabelResults(multiLabelResult: MultiLabelSelectionResult): ExplainMultiLabelResult[] {
  return multiLabelResult.selectedLabels.map((label) => ({
    selectedCategories: [label.category],
    rejectedCategories: [],
    coPresenceRulesApplied: [],
    maxLabelsLimit: 1,
    minSecondaryConfidence: 0,
    reason: label.selectionRationale,
  }));
}

/**
 * Build AI routing result for explainability trace
 */
function buildAIRoutingResult(aiRoutingResult: AIRoutingStageResult): AIRoutingResult | undefined {
  // AI routing is optional - only include if AI was actually used
  if (aiRoutingResult.routingDecision === 'skip_ai' && !aiRoutingResult.aiResponse) {
    return {
      routingDecision: aiRoutingResult.routingDecision,
      highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
      aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
      skipConditions: aiRoutingResult.skipConditions,
      reason: aiRoutingResult.reason,
    };
  }

  return {
    routingDecision: aiRoutingResult.routingDecision,
    highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
    aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
    skipConditions: aiRoutingResult.skipConditions,
    aiResponse: aiRoutingResult.aiResponse,
    reason: aiRoutingResult.reason,
  };
}

