/**
 * Unit tests for shared validation utilities
 *
 * Tests common validation patterns used across pipeline stages to ensure
 * consistent error handling and validation logic.
 */

import {
  validateEmailInput,
  validateSessionInput,
  validateConfigInput,
  validateConfidenceScore,
  validateConfidenceThreshold,
} from '../../src/utils/validation';
import { EmailMessage, ClassificationSession } from '../../src/types';

describe('validation utilities', () => {
  describe('validateEmailInput', () => {
    it('should pass for valid email with id', () => {
      const email: EmailMessage = {
        id: 'test-123',
        gmail_id: 'gmail-123',
        thread_id: 'thread-123',
        from: { name: 'Test', email: 'test@example.com' },
        to: [],
        subject: 'Test',
        date: new Date().toISOString(),
      };

      expect(() => validateEmailInput(email)).not.toThrow();
    });

    it('should pass for valid email with gmail_id only', () => {
      const email = {
        gmail_id: 'gmail-123',
        thread_id: 'thread-123',
        from: { name: 'Test', email: 'test@example.com' },
        to: [],
        subject: 'Test',
        date: new Date().toISOString(),
      } as unknown as EmailMessage;

      expect(() => validateEmailInput(email)).not.toThrow();
    });

    it('should throw for null email', () => {
      expect(() => validateEmailInput(null as unknown as EmailMessage)).toThrow(
        'Invalid email input: id or gmail_id is required'
      );
    });

    it('should throw for undefined email', () => {
      expect(() => validateEmailInput(undefined as unknown as EmailMessage)).toThrow(
        'Invalid email input: id or gmail_id is required'
      );
    });

    it('should throw for email missing both id and gmail_id', () => {
      const email = {
        thread_id: 'thread-123',
        from: { name: 'Test', email: 'test@example.com' },
      } as unknown as EmailMessage;

      expect(() => validateEmailInput(email)).toThrow('Invalid email input: id or gmail_id is required');
    });

    it('should throw for empty object', () => {
      expect(() => validateEmailInput({} as EmailMessage)).toThrow('Invalid email input: id or gmail_id is required');
    });
  });

  describe('validateSessionInput', () => {
    it('should pass for valid session with id', () => {
      const session: ClassificationSession = {
        id: 'session-123',
        started_at: new Date().toISOString(),
        completed_at: null,
        status: 'in_progress',
        total_emails: 10,
        emails_processed: 5,
        emails_failed: 0,
      };

      expect(() => validateSessionInput(session)).not.toThrow();
    });

    it('should pass for valid session with session_id only', () => {
      const session = {
        session_id: 'session-123',
        started_at: new Date().toISOString(),
      } as unknown as ClassificationSession;

      expect(() => validateSessionInput(session)).not.toThrow();
    });

    it('should throw for null session', () => {
      expect(() => validateSessionInput(null as unknown as ClassificationSession)).toThrow(
        'Invalid session input: id or session_id is required'
      );
    });

    it('should throw for undefined session', () => {
      expect(() => validateSessionInput(undefined as unknown as ClassificationSession)).toThrow(
        'Invalid session input: id or session_id is required'
      );
    });

    it('should throw for session missing both id and session_id', () => {
      const session = {
        started_at: new Date().toISOString(),
      } as unknown as ClassificationSession;

      expect(() => validateSessionInput(session)).toThrow('Invalid session input: id or session_id is required');
    });
  });

  describe('validateConfigInput', () => {
    it('should pass for valid object config', () => {
      const config = { setting: 'value', threshold: 0.5 };
      expect(() => validateConfigInput(config)).not.toThrow();
    });

    it('should pass for empty object config', () => {
      expect(() => validateConfigInput({})).not.toThrow();
    });

    it('should throw for null config', () => {
      expect(() => validateConfigInput(null)).toThrow('Configuration is required');
    });

    it('should throw for undefined config', () => {
      expect(() => validateConfigInput(undefined)).toThrow('Configuration is required');
    });

    it('should throw for non-object config (string)', () => {
      expect(() => validateConfigInput('config' as unknown as object)).toThrow('Configuration is required');
    });

    it('should throw for non-object config (number)', () => {
      expect(() => validateConfigInput(42 as unknown as object)).toThrow('Configuration is required');
    });

    it('should throw for non-object config (array)', () => {
      expect(() => validateConfigInput([] as unknown as object)).toThrow('Configuration is required');
    });
  });

  describe('validateConfidenceScore', () => {
    it('should pass for valid confidence scores', () => {
      expect(() => validateConfidenceScore(0)).not.toThrow();
      expect(() => validateConfidenceScore(0.5)).not.toThrow();
      expect(() => validateConfidenceScore(1)).not.toThrow();
      expect(() => validateConfidenceScore(0.85432)).not.toThrow();
    });

    it('should throw for NaN', () => {
      expect(() => validateConfidenceScore(NaN)).toThrow('Invalid confidence score');
    });

    it('should throw for Infinity', () => {
      expect(() => validateConfidenceScore(Infinity)).toThrow('Invalid confidence score');
    });

    it('should throw for -Infinity', () => {
      expect(() => validateConfidenceScore(-Infinity)).toThrow('Invalid confidence score');
    });

    it('should pass for negative scores (allowed)', () => {
      // Confidence scores can be negative in some contexts
      expect(() => validateConfidenceScore(-0.5)).not.toThrow();
    });

    it('should pass for scores > 1 (allowed)', () => {
      // Confidence scores can exceed 1 in some contexts
      expect(() => validateConfidenceScore(1.5)).not.toThrow();
    });
  });

  describe('validateConfidenceThreshold', () => {
    it('should pass for valid thresholds', () => {
      expect(() => validateConfidenceThreshold(0)).not.toThrow();
      expect(() => validateConfidenceThreshold(0.5)).not.toThrow();
      expect(() => validateConfidenceThreshold(1)).not.toThrow();
      expect(() => validateConfidenceThreshold(0.85)).not.toThrow();
    });

    it('should throw for threshold < 0', () => {
      expect(() => validateConfidenceThreshold(-0.1)).toThrow('Invalid confidence threshold');
    });

    it('should throw for threshold > 1', () => {
      expect(() => validateConfidenceThreshold(1.1)).toThrow('Invalid confidence threshold');
    });

    it('should throw for NaN', () => {
      expect(() => validateConfidenceThreshold(NaN)).toThrow('Invalid confidence threshold');
    });

    it('should throw for Infinity', () => {
      expect(() => validateConfidenceThreshold(Infinity)).toThrow('Invalid confidence threshold');
    });

    it('should throw for -Infinity', () => {
      expect(() => validateConfidenceThreshold(-Infinity)).toThrow('Invalid confidence threshold');
    });
  });
});

